 1	import { Th } from '@patternfly/react-table';
 2	
 3	import { buildSort } from './sort';
 4	import type { TableViewHeaderProps } from './types';
 5	
 6	/**
 7	 * A default table header with sortable columns.
 8	 *
 9	 * [<img src="static/media/src/components-stories/assets/github-logo.svg"><i class="fi fi-brands-github"></i>
10	 * <font color="green">View component source on GitHub</font>](https://github.com/kubev2v/forklift-console-plugin/blob/main/packages/common/src/components/TableView/DefaultHeader.tsx)
11	 */
12	export const DefaultHeader = <T,>({
13	  activeSort,
14	  setActiveSort,
15	  visibleColumns,
16	}: TableViewHeaderProps<T>) => {
17	  return (
18	    <>
19	      {visibleColumns.map(({ info, label, resourceFieldId, sortable }, columnIndex) => (
20	        <Th
21	          key={resourceFieldId}
22	          sort={
23	            sortable &&
24	            buildSort({
25	              activeSort,
26	              columnIndex,
27	              resourceFields: visibleColumns,
28	              setActiveSort,
29	            })
30	          }
31	          info={info}
32	        >
33	          {label}
34	        </Th>
35	      ))}
36	    </>
37	  );
38	};

